Hey guys I wrote a python script that does the same thing 

def american_to_prob(odds):
    """Convert American odds to implied probability (vig included)."""
    if odds > 0:
        return 100 / (odds + 100)
    else:
        return -odds / (-odds + 100)

def prob_to_american(prob):
    """Convert probability to American odds."""
    if prob == 0:
        return None
    elif prob < 0.5:
        return round((100 * (1 - prob)) / prob)
    else:
        return round(- (prob * 100) / (1 - prob))

def no_vig_calc(odds1, odds2):
    """Remove vig and return fair odds and probabilities."""
    prob1 = american_to_prob(odds1)
    prob2 = american_to_prob(odds2)

    total_prob = prob1 + prob2

    no_vig_prob1 = prob1 / total_prob
    no_vig_prob2 = prob2 / total_prob

    no_vig_odds1 = prob_to_american(no_vig_prob1)
    no_vig_odds2 = prob_to_american(no_vig_prob2)

    return {
        "Input Odds": (odds1, odds2),
        "No-Vig %": (round(no_vig_prob1 * 100, 2), round(no_vig_prob2 * 100, 2)),
        "No-Vig Odds": (no_vig_odds1, no_vig_odds2)
    }

# Example:
result = no_vig_calc(116, -154)
print(result)
